global void solver_2(int workload, int xmax, fp* x, fp* y, fp* params, fp* com, fp* err, fp* scale, fp* yy, fp* initvalu_temp, fp* finavalu_temp) {
    int bx = get_block_id(0);
    int tx = get_thread_id(0);
    int tid = bx*NUMBER_THREADS+tx;

    int err_pointer = tid*EQUATIONS;
    int scale_pointer = tid*EQUATIONS;
    int yy_pointer = tid*EQUATIONS;
    int params_pointer = tid*PARAMETERS;
    int initvalu_temp_pointer = tid*EQUATIONS;
    int finavalu_temp_pointer = tid*13*EQUATIONS;
    int com_pointer = tid*3;

    fp err_exponent = 1.0 / 7.0;
    fp h_init = 1;
    fp h = h_init;
    int xmin = 0;
    fp tolerance = 10 / (fp)(xmax - xmin);

    if (xmax < xmin || h <= 0.0){
        return;
    }
    if (xmax == xmin){
        return;
    }
    if (h > (xmax - xmin)) {
        h = (fp)xmax - (fp)xmin;
    }

    if(tid<workload){
        int k;
        for(k=1; k<(xmax+1); k++) {
            long y_pointer_initial = (long)tid*((xmax+1)*EQUATIONS)+(k-1)*EQUATIONS;
            long y_pointer_current = (long)tid*((xmax+1)*EQUATIONS)+k*EQUATIONS;
            long x_pointer_current = (long)tid*(xmax+1)+k;

            x[x_pointer_current] = (fp)k;
            h = h_init;
            fp scale_fina = 1.0;

            int j;
            for (j = 0; j < 12; j++) {
                int error = 0;
                int outside = 0;
                fp scale_min = 4.0;

                embedded_fehlberg_7_8_2(h, x[x_pointer_current], &y[y_pointer_initial], &y[y_pointer_current], &params[params_pointer], &err[err_pointer], &initvalu_temp[initvalu_temp_pointer], &finavalu_temp[finavalu_temp_pointer], &com[com_pointer]);

                int i;
                for(i=0; i<EQUATIONS; i++){
                    if(err[err_pointer+i] > 0){
                        error = 1;
                    }
                }
                if (error != 1) {
                    scale_fina = 4.0;
                    break;
                }

                for(i=0; i<EQUATIONS; i++){
                    if(y[y_pointer_initial+i] == 0.0){
                        yy[yy_pointer+i] = tolerance;
                    }
                    else{
                        yy[yy_pointer+i] = fabs(y[y_pointer_initial+i]);
                    }
                    scale[scale_pointer+i] = 0.8 * pow( tolerance * yy[yy_pointer+i] / err[err_pointer+i] , err_exponent );
                    if(scale[scale_pointer+i]<scale_min){
                        scale_min = scale[scale_pointer+i];
                    }
                }
                if (scale_min < 0.125) scale_min = 0.125;
                if (scale_min > 4.0) scale_min = 4.0;
                scale_fina = scale_min;

                for(i=0; i<EQUATIONS; i++){
                    if ( err[err_pointer+i] > ( tolerance * yy[yy_pointer+i] ) ){
                        outside = 1;
                    }
                }
                if (outside == 0){
                    break;
                }

                h = h * scale_fina;
                if (h >= 0.9) { h = 0.9; }
                if ( x[x_pointer_current] + h > (fp)xmax ){
                    h = (fp)xmax - x[x_pointer_current];
                }
                else if ( x[x_pointer_current] + h + 0.5 * h > (fp)xmax ){
                    h = 0.5 * h;
                }
            }

            x[x_pointer_current] = x[x_pointer_current] + h;
            if ( j >= 12 ) { return; }
        }
    }
